result = (store_returns.WHERE(
    (store.state == "TN") & (returned_date.year == 2000)
).PARTITION(
    name="store_customer_groups",
    by=(customer_key, store_key)
).CALCULATE(
    customer_total=SUM(store_returns.amount)
).PARTITION(
    name="store_groups", by=store_key
).CALCULATE(
    store_avg=1.2 * AVG(store_customer_groups.customer_total)
).store_customer_groups.WHERE(
    customer_total > store_avg
).store_returns.customer.CALCULATE(
    c_customer_id=_id
).TOP_K(10, by=c_customer_id))

selected_month_sold = sold_date.WHERE((month_of_year == 1) & (year == 2001))
result = items.PARTITION(
    name="item_category",
    by=category
).CALCULATE(
    category_avg=AVG(items.current_price)
).items.store_sales.WHERE(
    (HAS(selected_month_sold))
    & (item.current_price > 1.2*category_avg)
).customer.CALCULATE(
    state=current_address.state
).PARTITION(
    name="state", by=state
).CALCULATE(
    state,
    cnt=COUNT(customer)
).WHERE(cnt >= 10).TOP_K(10, by=(cnt, state))
